solution.code:
#include <stdio.h>

int main() {
    int n = 123, reversed = 0, original;
    original = n;
    while (n != 0) {
        int remainder = n % 10;
        reversed = reversed * 10 + remainder;
        n /= 10;
    }
    if (original == reversed) printf("Palindrome\n");
    else printf("Not Palindrome\n");
    return 0;
}
